def compute_top2_areas(sten_array):
    """CliftonStrengths 영역별 스텐 점수에서 상위 2개 영역 찾기"""
    if not sten_array or len(sten_array) < 4:
        return None

    AREA_KEYS = ['E', 'I', 'R', 'S']  # Executing, Influencing, Relationship, Strategic

    # (키, 값) 쌍 생성
    pairs = []
    for i, val in enumerate(sten_array):
        if val is not None:
            try:
                pairs.append((AREA_KEYS[i], float(val)))
            except (ValueError, TypeError):
                continue

    if len(pairs) < 2:
        return None

    # 값으로 내림차순 정렬, 동점 시 우선순위(E > I > R > S) 적용
    priority = {'E': 0, 'I': 1, 'R': 2, 'S': 3}
    pairs.sort(key=lambda x: (-x[1], priority[x[0]]))

    # 상위 2개 영역 조합
    top1 = pairs[0][0]
    top2 = pairs[1][0]

    return top1 + top2

